/**
 * ParticleBackground Component
 * Implements the "Antigravity" / Dotted mouse following theme using HTML5 Canvas
 */
const ParticleBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let width = window.innerWidth;
    let height = window.innerHeight;

    // Configuration
    const spacing = 40; // Space between dots
    const radius = 1.5; // Dot radius
    const mouseRadius = 150; // Influence radius of mouse
    const returnSpeed = 0.05; // Speed returning to origin
    const pushFactor = 4; // How strong the push is

    // Mouse state
    let mouseX = -1000;
    let mouseY = -1000;

    // Grid of points
    interface Point {
      x: number;
      y: number;
      originX: number;
      originY: number;
      vx: number;
      vy: number;
      color: string;
    }

    let points: Point[] = [];

    const init = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      canvas.width = width;
      canvas.height = height;
      points = [];

      // Create a grid of points
      const cols = Math.ceil(width / spacing);
      const rows = Math.ceil(height / spacing);

      for (let i = 0; i < cols; i++) {
        for (let j = 0; j < rows; j++) {
          const x = i * spacing + spacing / 2;
          const y = j * spacing + spacing / 2;

          // Random slight offset for organic feel
          const offsetX = (Math.random() - 0.5) * 10;
          const offsetY = (Math.random() - 0.5) * 10;

          // Color variation based on position to mimic galaxy
          // Deep blues, purples, and faint whites
          const r = Math.random();
          let color = 'rgba(255, 255, 255, 0.2)'; // Default faint star
          if (r > 0.90) color = 'rgba(147, 51, 234, 0.6)'; // Purple
          else if (r > 0.80) color = 'rgba(59, 130, 246, 0.6)'; // Blue

          points.push({
            x: x + offsetX,
            y: y + offsetY,
            originX: x + offsetX,
            originY: y + offsetY,
            vx: 0,
            vy: 0,
            color
          });
        }
      }
    };

    const animate = () => {
      ctx.clearRect(0, 0, width, height);

      points.forEach(point => {
        // Calculate distance to mouse
        const dx = mouseX - point.x;
        const dy = mouseY - point.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Physics: Repulse from mouse
        if (distance < mouseRadius) {
            const forceDirectionX = dx / distance;
            const forceDirectionY = dy / distance;
            const force = (mouseRadius - distance) / mouseRadius;

            // Push away
            const directionX = forceDirectionX * force * pushFactor;
            const directionY = forceDirectionY * force * pushFactor;

            point.vx -= directionX;
            point.vy -= directionY;
        }

        // Physics: Return to origin (Elasticity)
        const homeDx = point.originX - point.x;
        const homeDy = point.originY - point.y;

        point.vx += homeDx * returnSpeed;
        point.vy += homeDy * returnSpeed;

        // Friction (Dampening)
        point.vx *= 0.85;
        point.vy *= 0.85;

        // Update position
        point.x += point.vx;
        point.y += point.vy;

        // Draw point
        ctx.beginPath();
        ctx.arc(point.x, point.y, radius, 0, Math.PI * 2);
        ctx.fillStyle = point.color;
        ctx.fill();
      });

      animationFrameId = requestAnimationFrame(animate);
    };

    const handleMouseMove = (e: MouseEvent) => {
      mouseX = e.clientX;
      mouseY = e.clientY;
    };

    const handleResize = () => {
      init();
    };

    // Listeners
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('resize', handleResize);

    // Initial Start
    init();
    animate();

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('resize', handleResize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed top-0 left-0 w-full h-full pointer-events-none z-0"
    />
  );
};

